// Beads is the resolver for the beads field.
func (r *queryResolver) Beads(ctx context.Context, first *int, after *string, last *int, before *string, status *string, label *string, projectID *string) (*BeadConnection, error) {
	statusVal := ""
	if status != nil {
		statusVal = *status
	}
	labelVal := ""
	if label != nil {
		labelVal = *label
	}
	projectIDVal := ""
	if projectID != nil {
		projectIDVal = *projectID
	}
	snaps := r.State.GetBeadSnapshots(statusVal, labelVal, projectIDVal, "")
	return beadConnectionFromSnapshots(snaps, first, after, last, before), nil
}

// BeadsByProject is the resolver for the beadsByProject field.
func (r *queryResolver) BeadsByProject(ctx context.Context, projectID string, first *int, after *string, last *int, before *string, status *string, label *string, search *string) (*BeadConnection, error) {
	statusVal := ""
	if status != nil {
		statusVal = *status
	}
	labelVal := ""
	if label != nil {
		labelVal = *label
	}
	searchVal := ""
	if search != nil {
		searchVal = *search
	}
	snaps := r.State.GetBeadSnapshots(statusVal, labelVal, projectID, searchVal)
	return beadConnectionFromSnapshots(snaps, first, after, last, before), nil
}

func beadConnectionFromSnapshots(snaps []BeadSnapshot, first *int, after *string, last *int, before *string) *BeadConnection {
	// Build full edge list with stable ID-based cursors.
	all := make([]*BeadEdge, len(snaps))
	for i, s := range snaps {
		all[i] = &BeadEdge{
			Node:   beadFromSnapshot(s),
			Cursor: encodeStableCursor(s.ID),
		}
	}

	// Apply window: start after `after` cursor, end before `before` cursor.
	startIdx := 0
	if after != nil {
		if afterID, ok := decodeStableCursor(*after); ok {
			for i, e := range all {
				if e.Node.ID == afterID {
					startIdx = i + 1
					break
				}
			}
		}
	}
	endIdx := len(all)
	if before != nil {
		if beforeID, ok := decodeStableCursor(*before); ok {
			for i, e := range all {
				if e.Node.ID == beforeID {
					endIdx = i
					break
				}
			}
		}
	}
	if startIdx > endIdx {
		startIdx = endIdx
	}

	slice := all[startIdx:endIdx]
	truncatedByFirst := false
	truncatedByLast := false
	if first != nil && *first >= 0 && *first < len(slice) {
		slice = slice[:*first]
		truncatedByFirst = true
	}
	if last != nil && *last >= 0 && *last < len(slice) {
		slice = slice[len(slice)-*last:]
		truncatedByLast = true
	}

	pageInfo := &PageInfo{
		HasPreviousPage: startIdx > 0 || truncatedByLast,
		HasNextPage:     endIdx < len(all) || truncatedByFirst,
	}
	if len(slice) > 0 {
		pageInfo.StartCursor = &slice[0].Cursor
		pageInfo.EndCursor = &slice[len(slice)-1].Cursor
	}

	return &BeadConnection{
		Edges:      slice,
		PageInfo:   pageInfo,
		TotalCount: len(all),
	}
}

func beadFromSnapshot(s BeadSnapshot) *Bead {
	b := &Bead{
		ID:        s.ID,
		Title:     s.Title,
		Status:    s.Status,
		Priority:  s.Priority,
		IssueType: s.IssueType,
		CreatedAt: s.CreatedAt.UTC().Format(time.RFC3339),
		UpdatedAt: s.UpdatedAt.UTC().Format(time.RFC3339),
		Labels:    s.Labels,
	}
	if s.ProjectID != "" {
		b.ProjectID = &s.ProjectID
	}
	if s.Owner != "" {
		b.Owner = &s.Owner
	}
	if s.CreatedBy != "" {
		b.CreatedBy = &s.CreatedBy
	}
	if s.Parent != "" {
		b.Parent = &s.Parent
	}
	if s.Description != "" {
		b.Description = &s.Description
	}
	if s.Acceptance != "" {
		b.Acceptance = &s.Acceptance
	}
	if s.Notes != "" {
		b.Notes = &s.Notes
	}

package graphql

import (
	"context"
	"fmt"
	"path/filepath"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// beadStore returns a bead.Store rooted at the resolver's working directory.
func (r *mutationResolver) beadStore() *bead.Store {
	return bead.NewStore(filepath.Join(r.WorkingDir, ".ddx"))
}

// beadModelFromBead converts a bead.Bead to the GraphQL Bead model.
func beadModelFromBead(b *bead.Bead) *Bead {
	gql := &Bead{
		ID:        b.ID,
		Title:     b.Title,
		Status:    b.Status,
		Priority:  b.Priority,
		IssueType: b.IssueType,
		CreatedAt: b.CreatedAt.UTC().Format(time.RFC3339),
		UpdatedAt: b.UpdatedAt.UTC().Format(time.RFC3339),
		Labels:    b.Labels,
	}
	if b.Owner != "" {
		gql.Owner = &b.Owner
	}
	if b.CreatedBy != "" {
		gql.CreatedBy = &b.CreatedBy
	}
	if b.Parent != "" {
		gql.Parent = &b.Parent
	}
	if b.Description != "" {
		gql.Description = &b.Description
	}
	if b.Acceptance != "" {
		gql.Acceptance = &b.Acceptance
	}
	if b.Notes != "" {
		gql.Notes = &b.Notes
	}
	for _, d := range b.Dependencies {
		dep := &Dependency{
			IssueID:     d.IssueID,
			DependsOnID: d.DependsOnID,
			Type:        d.Type,
		}
		if d.CreatedAt != "" {
			dep.CreatedAt = &d.CreatedAt
		}
		if d.CreatedBy != "" {
			dep.CreatedBy = &d.CreatedBy
		}
		if d.Metadata != "" {
			dep.Metadata = &d.Metadata
		}
		gql.Dependencies = append(gql.Dependencies, dep)
	}
	return gql
}

// BeadCreate is the resolver for the beadCreate mutation.
func (r *mutationResolver) BeadCreate(ctx context.Context, input BeadInput) (*Bead, error) {
	if r.WorkingDir == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	if input.Title == "" {
		return nil, fmt.Errorf("title is required")
	}

	b := &bead.Bead{
		Title: input.Title,
	}
	if input.Status != nil {
		b.Status = *input.Status
	}
	if input.Priority != nil {
		b.Priority = *input.Priority
	}
	if input.IssueType != nil {
		b.IssueType = *input.IssueType
	}
	if input.Labels != nil {
		b.Labels = input.Labels
	}
	if input.Parent != nil {
		b.Parent = *input.Parent
	}
	if input.Description != nil {
		b.Description = *input.Description
	}
	if input.Acceptance != nil {
		b.Acceptance = *input.Acceptance
	}
	if input.Notes != nil {
		b.Notes = *input.Notes
	}

	store := r.beadStore()
	if err := store.Create(b); err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadUpdate is the resolver for the beadUpdate mutation.
func (r *mutationResolver) BeadUpdate(ctx context.Context, id string, input BeadUpdateInput) (*Bead, error) {
	if r.WorkingDir == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore()
	err := store.Update(id, func(b *bead.Bead) {
		if input.Title != nil {
			b.Title = *input.Title
		}
		if input.Status != nil {
			b.Status = *input.Status
		}
		if input.Priority != nil {
			b.Priority = *input.Priority
		}
		if input.IssueType != nil {
			b.IssueType = *input.IssueType
		}
		if input.Labels != nil {
			b.Labels = input.Labels
		}
		if input.Parent != nil {
			b.Parent = *input.Parent
		}
		if input.Description != nil {
			b.Description = *input.Description
		}
		if input.Acceptance != nil {
			b.Acceptance = *input.Acceptance
		}
		if input.Notes != nil {
			b.Notes = *input.Notes
		}
	})
	if err != nil {
		return nil, err
	}

	b, err := store.Get(id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadClaim is the resolver for the beadClaim mutation.
func (r *mutationResolver) BeadClaim(ctx context.Context, id string, assignee string) (*Bead, error) {
	if r.WorkingDir == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore()
	if err := store.Claim(id, assignee); err != nil {
		return nil, err
	}

	b, err := store.Get(id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadUnclaim is the resolver for the beadUnclaim mutation.
func (r *mutationResolver) BeadUnclaim(ctx context.Context, id string) (*Bead, error) {
	if r.WorkingDir == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore()
	if err := store.Unclaim(id); err != nil {
		return nil, err
	}

	b, err := store.Get(id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadReopen is the resolver for the beadReopen mutation.
func (r *mutationResolver) BeadReopen(ctx context.Context, id string) (*Bead, error) {
	if r.WorkingDir == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore()
	err := store.Update(id, func(b *bead.Bead) {
		b.Status = bead.StatusOpen
		b.Owner = ""
	})
	if err != nil {
		return nil, err
	}

	b, err := store.Get(id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

